        // Unstable value U(i) = max(nums[0...i]) - min(nums[i...n-1])
        const unstableValue = prefixMax[i] - suffixMin[i];

        if (unstableValue <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}

