function solve(nums, k) {
    const n = nums.length;

    if (n === 0) {
        return -1;
    }

    // 1. Calculate Prefix Maximums: prefixMax[i] = max(nums[0...i])
    const prefixMax = new Array(n);
    prefixMax[0] = nums[0];
    for (let i = 1; i < n; i++) {
        prefixMax[i] = Math.max(prefixMax[i - 1], nums[i]);
    }

    // 2. Calculate Suffix Minimums: suffixMin[i] = min(nums[i...n-1])
    const suffixMin = new Array(n);
    suffixMin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) {
        suffixMin[i] = Math.min(suffixMin[i + 1], nums[i]);
    }

    // 3. Iterate and find the smallest stable index i
    for (let i = 0; i < n; i++) {
        // Unstable value U(i) = max(nums[0...i]) - min(nums[i...n-1])
        const unstableValue = prefixMax[i] - suffixMin[i];

        if (unstableValue <= k) {
            return i;
        }
    }

    // If no stable index is found
    return -1;
}
